#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-02

# Integration test: cc-release-watch.mjs end-to-end against synthetic fixture.
# Verifies snapshot writes, gap report shape, idempotence, and issue-args emission.
# No network, no LLM, no actual gh issue create — pure file-system effects.
# Issue: #1486 (M130)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC Release Watch Tests (M130 #1486)"
echo "==================================="

cd "$PROJECT_ROOT"

# Save state we'll mutate during tests. Errors during backup are real (FS issue, perm denied)
# and should fail the test rather than be hidden.
SNAPSHOTS_BACKUP=$(mktemp -d)
if [ -d shared/cc-snapshots ]; then
  # rsync rather than cp -r/. so we don't need shell-glob expansion of dotfiles.
  rsync -a shared/cc-snapshots/ "$SNAPSHOTS_BACKUP/"
fi
GAPS_BACKUP=""
[ -f shared/cc-adoption-gaps.json ] && GAPS_BACKUP=$(cat shared/cc-adoption-gaps.json)
ARGS_BACKUP=""
[ -f shared/gh-issue-args.json ] && ARGS_BACKUP=$(cat shared/gh-issue-args.json)

restore() {
  rm -rf shared/cc-snapshots
  mkdir -p shared/cc-snapshots
  if [ -d "$SNAPSHOTS_BACKUP" ] && [ -n "$(ls -A "$SNAPSHOTS_BACKUP" 2>&1)" ]; then
    rsync -a "$SNAPSHOTS_BACKUP/" shared/cc-snapshots/
  fi
  rm -rf "$SNAPSHOTS_BACKUP"
  if [ -n "$GAPS_BACKUP" ]; then
    echo "$GAPS_BACKUP" > shared/cc-adoption-gaps.json
  else
    rm -f shared/cc-adoption-gaps.json
  fi
  if [ -n "$ARGS_BACKUP" ]; then
    echo "$ARGS_BACKUP" > shared/gh-issue-args.json
  else
    rm -f shared/gh-issue-args.json
  fi
}
trap restore EXIT

# Reset to clean state for tests
rm -rf shared/cc-snapshots/*.md shared/cc-adoption-gaps.json shared/gh-issue-args.json

# Pre-populate snapshots for every prior version that's <= cc-support.json.latest
# to simulate the production steady state. This isolates Test 1 to the "one new
# version" scenario (2.1.148 — a synthetic future version above the current
# floor of 2.1.138) without triggering the M130-hotfix recovery path that
# re-snapshots equal-version-but-missing-on-disk entries (covered by a
# dedicated test below). The fixture pins 2.1.148 specifically so this test
# is resilient to future floor bumps in shared/cc-support.json.
mkdir -p shared/cc-snapshots
for v in 2.1.126 2.1.127 2.1.128 2.1.129 2.1.131 2.1.132 2.1.133 2.1.136 2.1.137 2.1.138; do
  echo "# Claude Code $v (placeholder for test)" > "shared/cc-snapshots/$v.md"
done

# ============================================================================
# Test 1: fixture with one new version → writes snapshot + gaps + args
# ============================================================================
CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/synthetic.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-out.txt 2>&1

if [ -f shared/cc-snapshots/2.1.148.md ]; then
  log_pass "Snapshot written for new version 2.1.148"
else
  log_fail "Snapshot missing" "expected shared/cc-snapshots/2.1.148.md (see /tmp/watch-out.txt)"
fi

if [ -f shared/cc-snapshots/2.1.148.md ] && grep -qF "EnterWorktree" shared/cc-snapshots/2.1.148.md; then
  log_pass "Snapshot body contains expected feature bullet"
else
  log_fail "Snapshot body" "missing 'EnterWorktree' from fixture"
fi

if [ -f shared/cc-adoption-gaps.json ]; then
  COUNT=$(jq 'length' shared/cc-adoption-gaps.json)
  if [ "$COUNT" = "1" ]; then
    log_pass "Gaps JSON has exactly 1 entry"
    GAP_VERSION=$(jq -r '.[0].version' shared/cc-adoption-gaps.json)
    if [ "$GAP_VERSION" = "2.1.148" ]; then
      log_pass "Gap entry version = 2.1.148"
    else
      log_fail "Gap entry version" "expected 2.1.148, got '$GAP_VERSION'"
    fi
  else
    log_fail "Gaps JSON entry count" "expected 1, got $COUNT"
  fi
else
  log_fail "Gaps JSON" "shared/cc-adoption-gaps.json was not written"
fi

if [ -f shared/gh-issue-args.json ]; then
  TITLE=$(jq -r '.milestone' shared/gh-issue-args.json)
  # Single rolling umbrella: the milestone title is now CONSTANT across
  # versions ("CC adoption"), not "CC X.Y.Z adoption" per version.
  if [ "$TITLE" = "CC adoption" ]; then
    log_pass "gh-issue-args milestone title = 'CC adoption' (single rolling umbrella)"
  else
    log_fail "milestone title" "expected 'CC adoption', got '$TITLE'"
  fi
  # Per-version traceability is preserved in latest_new_version even though
  # the milestone no longer encodes the version.
  LATEST=$(jq -r '.latest_new_version' shared/gh-issue-args.json)
  if [ "$LATEST" = "2.1.148" ]; then
    log_pass "gh-issue-args latest_new_version = 2.1.148 (per-version trace kept)"
  else
    log_fail "latest_new_version" "expected 2.1.148, got '$LATEST'"
  fi
else
  log_fail "gh-issue-args.json missing" "expected emitted by watch script"
fi

# ============================================================================
# Test 2: idempotent — re-running with same fixture produces no-op
# ============================================================================
CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/synthetic.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-out2.txt 2>&1

if grep -qF "nothing new" /tmp/watch-out2.txt; then
  log_pass "Idempotent on second run with same fixture"
else
  log_fail "Idempotent check" "expected 'nothing new', got: $(tail -2 /tmp/watch-out2.txt)"
fi

if [ -f shared/cc-adoption-gaps.json ] && [ "$(jq 'length' shared/cc-adoption-gaps.json)" = "0" ]; then
  log_pass "Gaps JSON cleared to [] on no-op run"
else
  log_fail "Idempotent gaps clear" "expected length 0 after no-op"
fi

# ============================================================================
# Test 3: snapshot file persists across no-op runs
# ============================================================================
if [ -f shared/cc-snapshots/2.1.128.md ]; then
  log_pass "Snapshot persists across no-op runs"
else
  log_fail "Snapshot persistence" "shared/cc-snapshots/2.1.128.md disappeared"
fi

# ============================================================================
# Test 4: recovery path — equal-version + missing snapshot is re-included
# (M130 hotfix). Pinned to cc-support.json.latest's value (2.1.138 today) so
# this test stays aligned with the floor whenever the support window bumps.
# Removes the latest's snapshot from disk; rerunning must re-snapshot it
# instead of silently skipping.
# ============================================================================
RECOVERY_VERSION=$(jq -r '.latest' shared/cc-support.json)
rm -f "shared/cc-snapshots/${RECOVERY_VERSION}.md"
rm -f shared/cc-adoption-gaps.json shared/gh-issue-args.json

CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/synthetic.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-recover.txt 2>&1

if [ -f "shared/cc-snapshots/${RECOVERY_VERSION}.md" ]; then
  log_pass "Recovery: missing equal-version snapshot re-created on next run (${RECOVERY_VERSION})"
else
  log_fail "Recovery snapshot" "expected ${RECOVERY_VERSION}.md to be re-written when missing on disk"
fi

# Restore the latest snapshot so subsequent tests start from a steady state.
echo "# Claude Code ${RECOVERY_VERSION} (placeholder for test)" > "shared/cc-snapshots/${RECOVERY_VERSION}.md"

# ============================================================================
# Test 5: double-dash bullet normalization (regression for CC 2.1.126 parse fail)
# Upstream CHANGELOG sometimes has `- - Added foo` typos; the watcher must
# collapse them to single-dash so cc-triage.mjs's LLM call sees clean input.
# ============================================================================
rm -f shared/cc-snapshots/2.1.998.md shared/cc-adoption-gaps.json shared/gh-issue-args.json

CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/double-dash.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-double-dash.txt 2>&1

if [ -f shared/cc-snapshots/2.1.998.md ]; then
  log_pass "Double-dash fixture: snapshot written for 2.1.998"
else
  log_fail "Double-dash snapshot" "expected shared/cc-snapshots/2.1.998.md"
fi

# Body must be normalized — no `- - ` lines should survive into the snapshot.
if [ -f shared/cc-snapshots/2.1.998.md ]; then
  if grep -qE '^- - ' shared/cc-snapshots/2.1.998.md; then
    log_fail "Double-dash normalization" "snapshot still contains '- - ' prefix"
  else
    log_pass "Double-dash normalization: no '- - ' prefix in snapshot body"
  fi
  if grep -qF -- '- Added `claude project foo`' shared/cc-snapshots/2.1.998.md; then
    log_pass "Double-dash normalization: collapsed to single '- ' prefix"
  else
    log_fail "Double-dash content" "expected single-dash bullet for collapsed line"
  fi
fi

# raw_bullets_count must reflect actual bullet count after normalization (3, not skewed).
if [ -f shared/cc-adoption-gaps.json ]; then
  COUNT=$(jq -r '.[] | select(.version=="2.1.998") | .raw_bullets_count' shared/cc-adoption-gaps.json)
  if [ "$COUNT" = "3" ]; then
    log_pass "Double-dash raw_bullets_count = 3 (post-normalization)"
  else
    log_fail "raw_bullets_count" "expected 3, got '$COUNT'"
  fi
fi

# Restore steady state for any subsequent test additions.
rm -f shared/cc-snapshots/2.1.998.md shared/cc-adoption-gaps.json shared/gh-issue-args.json
echo '# Claude Code 2.1.126 (placeholder for test)' > shared/cc-snapshots/2.1.126.md

# ============================================================================
# Test 6: W1b (#1693) — versions OLDER than knownLatest but missing on disk
# must still be picked up. Earlier `cmp >= 0` filter caused permanently
# invisible failure mode when cc-support.json.latest jumped past versions.
# ============================================================================
rm -f shared/cc-snapshots/2.1.13[345].md shared/cc-adoption-gaps.json shared/gh-issue-args.json
# Pre-populate 2.1.135 only — simulating "floor jumped to 135 but 133/134
# never got snapshotted on disk". cc-support.json.latest is 2.1.132 today,
# so use a temporary override via env reading: the script reads support.latest
# directly. We simulate by leaving 2.1.135 snapshotted and 133/134 missing,
# and we exploit the fact that the W1b filter must include versions
# regardless of relation to knownLatest, as long as they're missing on disk.
echo "# Claude Code 2.1.135 (placeholder)" > shared/cc-snapshots/2.1.135.md

CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/support-latest-ahead.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-w1b.txt 2>&1

if [ -f shared/cc-snapshots/2.1.133.md ] && [ -f shared/cc-snapshots/2.1.134.md ]; then
  log_pass "W1b: missing-on-disk versions older than nothing-vs-floor are snapshotted"
else
  log_fail "W1b snapshot recovery" "expected 2.1.133.md AND 2.1.134.md to be re-snapshotted (see /tmp/watch-w1b.txt)"
fi

# 2.1.135 was already snapshotted — must remain a no-op for it (W1b filter
# is "snapshotted-on-disk" not "compare against floor").
if [ -f shared/cc-adoption-gaps.json ]; then
  HAS_135=$(jq -r '.[] | select(.version=="2.1.135") | .version' shared/cc-adoption-gaps.json)
  if [ -z "$HAS_135" ]; then
    log_pass "W1b: already-snapshotted 2.1.135 is NOT re-emitted in gaps"
  else
    log_fail "W1b: 2.1.135 leaked into gaps" "expected absent, got '$HAS_135'"
  fi
fi

# Restore steady state.
rm -f shared/cc-snapshots/2.1.13[345].md shared/cc-adoption-gaps.json shared/gh-issue-args.json

# ============================================================================
# Test 7: W1c (#1694) — `--reissue-existing X.Y.Z` re-emits gap entry without
# overwriting existing snapshot file body.
# ============================================================================
# Set up: 2.1.133 snapshot exists with custom body. Run with --reissue-existing
# 2.1.133. Expect: snapshot body unchanged, gap entry emitted with empty features.
mkdir -p shared/cc-snapshots
cat > shared/cc-snapshots/2.1.133.md <<'EOF'
# Claude Code 2.1.133

CUSTOM_BODY_THAT_SHOULD_NOT_BE_OVERWRITTEN

- existing bullet 1
- existing bullet 2
EOF

# Pre-populate 2.1.135 too so the watcher doesn't try to fetch it.
echo "# Claude Code 2.1.135 (placeholder)" > shared/cc-snapshots/2.1.135.md
echo "# Claude Code 2.1.134 (placeholder)" > shared/cc-snapshots/2.1.134.md

CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/support-latest-ahead.md \
  node scripts/cc-release-watch.mjs --reissue-existing 2.1.133 > /tmp/watch-w1c.txt 2>&1

if grep -qF "CUSTOM_BODY_THAT_SHOULD_NOT_BE_OVERWRITTEN" shared/cc-snapshots/2.1.133.md; then
  log_pass "W1c: --reissue-existing keeps existing snapshot body"
else
  log_fail "W1c: snapshot overwritten" "custom body lost — see shared/cc-snapshots/2.1.133.md"
fi

if [ -f shared/cc-adoption-gaps.json ]; then
  HAS_133=$(jq -r '.[] | select(.version=="2.1.133") | .version' shared/cc-adoption-gaps.json)
  if [ "$HAS_133" = "2.1.133" ]; then
    log_pass "W1c: --reissue-existing re-emits gap entry for 2.1.133"
  else
    log_fail "W1c: gap not re-emitted" "expected 2.1.133, got '$HAS_133' (cat /tmp/watch-w1c.txt)"
  fi
  EMPTY_FEATURES=$(jq -r '.[] | select(.version=="2.1.133") | .features | length' shared/cc-adoption-gaps.json)
  if [ "$EMPTY_FEATURES" = "0" ]; then
    log_pass "W1c: reissued gap entry has empty features[] (ready for triage)"
  else
    log_fail "W1c: features should be []" "got length=$EMPTY_FEATURES"
  fi
fi

if grep -qF "reissue: " /tmp/watch-w1c.txt; then
  log_pass "W1c: explicit reissue log emitted"
else
  log_fail "W1c log" "expected 'reissue:' line in stdout"
fi

# Comma-separated form
rm -f shared/cc-adoption-gaps.json shared/gh-issue-args.json
CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/support-latest-ahead.md \
  node scripts/cc-release-watch.mjs --reissue-existing 2.1.133,2.1.134 > /tmp/watch-w1c2.txt 2>&1

if [ -f shared/cc-adoption-gaps.json ]; then
  COUNT=$(jq -r '[.[] | select(.version=="2.1.133" or .version=="2.1.134")] | length' shared/cc-adoption-gaps.json)
  if [ "$COUNT" = "2" ]; then
    log_pass "W1c: comma-separated --reissue-existing reissues both versions"
  else
    log_fail "W1c: comma form" "expected 2 reissued entries, got $COUNT"
  fi
fi

# Cleanup before final test
rm -f shared/cc-snapshots/2.1.13[345].md shared/cc-adoption-gaps.json shared/gh-issue-args.json

# ============================================================================
# Test 8: missing fixture path errors cleanly (exit 1)
# ============================================================================
EXIT=0
CC_RELEASE_WATCH_FIXTURE=/nonexistent/path.md node scripts/cc-release-watch.mjs > /tmp/watch-err.txt 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ]; then
  log_fail "Missing fixture handling" "script returned 0 on missing fixture"
else
  if grep -qF "fixture not found" /tmp/watch-err.txt; then
    log_pass "Missing fixture errors with clear message"
  else
    log_fail "Missing fixture message" "expected 'fixture not found', got: $(cat /tmp/watch-err.txt)"
  fi
fi

echo ""
echo "==================================="
echo "  Results: $PASS passed, $FAIL failed"
echo "==================================="

if [[ $FAIL -gt 0 ]]; then
  echo -e "${RED}FAIL${NC}"
  exit 1
fi
echo -e "${GREEN}SUCCESS${NC}"
